<?php
namespace App\Http\Controllers\Admin; use App\Http\Controllers\Controller; use App\Models\Role; use App\Services\ActivityLogger; use Illuminate\Http\RedirectResponse; use Illuminate\Http\Request; use Illuminate\Support\Str; use Illuminate\View\View;
class RoleController extends Controller { private array $available=['admin.access','servers.manage','servers.query','users.manage','roles.manage','modules.manage','settings.manage','bans.manage','rcon.execute','shop.manage']; public function index():View{return view('admin.roles.index',['roles'=>Role::withCount('users')->orderByDesc('is_system')->get()]);} public function create():View{return view('admin.roles.form',['role'=>new Role,'available'=>$this->available]);} public function store(Request $r,ActivityLogger $log):RedirectResponse{$role=Role::create($this->data($r));$log->record('role.created',$role);return to_route('admin.roles.index')->with('success','Ролята е създадена.');} public function edit(Role $role):View{return view('admin.roles.form',compact('role')+['available'=>$this->available]);} public function update(Request $r,Role $role,ActivityLogger $log):RedirectResponse{abort_if($role->is_system,403);$role->update($this->data($r,$role));$log->record('role.updated',$role);return back()->with('success','Ролята е обновена.');} public function destroy(Role $role,ActivityLogger $log):RedirectResponse{abort_if($role->is_system||$role->users()->exists(),422);$log->record('role.deleted',$role);$role->delete();return back()->with('success','Ролята е изтрита.');} private function data(Request $r,?Role $role=null):array{$d=$r->validate(['name'=>['required','string','max:80'],'permissions'=>['array'],'permissions.*'=>['in:'.implode(',',$this->available)]]);$d['slug']=$role?->slug??Str::slug($d['name']).'-'.Str::lower(Str::random(4));$d['permissions']=$d['permissions']??[];return $d;} }
